namespace _4re5_manager
{
    public class Data
    {
        public static string version = "1.0";
        public static string banner = "";
        public static string appIcon = "";
        public static string exitIcon = "";
        public static string searchIcon = "";
        public static string minimizeIcon = "";
    }
    public enum Platform
    {
        Windows,
        Android,
        Linux
    }
    public class AresApp
    {
        public required string name = "";
        public required string description = "Error While Loading Description";
        public required string image;
        public required string version = "-1.0.0";
        public required string first_date = "01-01-1970";
        public required string last_update = "01-01-1970";
        public required string[] updates = [];
        public required string author = "";
        public required string license = "";
        public required string package = "";
        public required Platform[] platform = [];
        public required string url = "";
        public required bool disabled = false;
        public required string[] keywords = [];
        public required string[] install_requires = [];
        public required bool installed = false;
        public required bool isCmdTool = false;
        public required string startUpFile = "";
        public required bool isZipped=false;
        public required bool isInstaller=false;
    }
    public partial class Form1 : Form
    {
        public bool modeIsAvailableOrInstalled = true;
        public string appPath = "";
        private string repoUrl = @"https://raw.githubusercontent.com/4RE5group/4re5-repository/refs/heads/main/repo.json";
        private List<AresApp> appList = new List<AresApp>();
        private AresApp selectedApp = null;

        private bool dragging = false;
        private Point dragCursorPoint;
        private Point dragFormPoint;


        private void window_MouseDown(object sender, MouseEventArgs e)
        {
            dragging = true;
            dragCursorPoint = Cursor.Position;
            dragFormPoint = this.Location;
        }

        private void window_MouseMove(object sender, MouseEventArgs e)
        {
            if (dragging)
            {
                Point delta = new Point(Cursor.Position.X - dragCursorPoint.X, Cursor.Position.Y - dragCursorPoint.Y);
                this.Location = new Point(dragFormPoint.X + delta.X, dragFormPoint.Y + delta.Y);
            }
        }

        private void window_MouseUp(object sender, MouseEventArgs e)
        {
            dragging = false;
        }

        public Form1()
        {
            InitializeComponent();

            appBtnUninstall.Visible = false;
            appBtnInstall.Visible = false;
            label2.Visible = false;
            appVersion.Text = "";
            appDesc.Text = "";
            appName.Text = "";
            appIcon.Image = null;
            appBtnInstall.Click += installPackage;
            appBtnUninstall.Click += uninstallPackage;

            string appData = Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData);
            appPath = Path.Combine(appData, "4re5 group");

            FetchRepo();
            searchPackageThenDisplay("");

        }
        private Image LoadImageFromUrl(string url)
        {
            using (var client = new HttpClient())
            {
                try
                {

                    using (var response = client.GetAsync(url).Result) // Attendre la réponse synchronement
                    {
                        if (response.IsSuccessStatusCode)
                        {
                            using (var s = response.Content.ReadAsStreamAsync().Result) // Attendre le stream synchronement
                            {
                                return Image.FromStream(s);
                            }
                        }
                        else
                        {
                            throw new Exception();
                        }
                    }
                }
                catch {
                    //MessageBox.Show("Could not load image url=>'" + url + "'");
                    return (Image)null;
                }
            }
        }
        private void installPackage(object s, EventArgs e)
        {
            if(selectedApp != null)
            {
                if(appBtnInstall.Text == "Launch")
                {
                    if(selectedApp != null)
                    {
                        string startPath = Path.Join(appPath, selectedApp.package, selectedApp.startUpFile);
                        
                        if(!File.Exists(startPath))
                        {
                            MessageBox.Show("Could not launch app, try reinstalling package");
                            return;
                        }
                        
                        if (selectedApp.isCmdTool) // console app
                        {
                            ProcessStartInfo psi = new ProcessStartInfo
                            {
                                FileName = "cmd.exe",
                                Arguments = "/K cd \""+ Path.Join(appPath, selectedApp.package)+ "\" && call \""+startPath+"\"", 
                                UseShellExecute = true
                            };

                            Process.Start(psi);
                        } else // winExe
                        {
                            ProcessStartInfo psi = new ProcessStartInfo
                            {
                                FileName = startPath,
                                Arguments = "",
                                UseShellExecute = true
                            };

                            Process.Start(psi);
                        }
                    }
                } else // install package
                {
                    DownloadPackage(selectedApp);
                }
                    
            }
        }
        private void uninstallPackage(object s, EventArgs e)
        {
            appBtnUninstall.Visible = false;
            appBtnInstall.Text = "Install";
            selectedApp.installed = false;

            string appDir = Path.Join(appPath, selectedApp.package);
            if(Directory.Exists(appDir))
            {
                Directory.Delete(appDir, true);
            } else
            {
                MessageBox.Show("Error while uninstalling software");
            }
        }
        private void searchPackageThenDisplay(string name)
        {
            appsList.Controls.Clear(); // clear list
            int i = 0;
            foreach (AresApp app in appList)
            {
                if(app.name.ToLower().StartsWith(name) || name=="")
                {
                    if (app.disabled)
                        continue;
                    Image appicon;
                    using (MemoryStream ms = new MemoryStream(Convert.FromBase64String(Data.searchIcon)))
                    {
                        appicon = Image.FromStream(ms);
                    }
                    ListGenerator.AddAppPanel(appsList, i, app.name, app.description, string.Join(",", app.platform), appicon, (s, e) => { 
                        MessageBox.Show("Downloading...");
                    }, (s, e) => {
                        DisplayApp(app);
                    });

                    i++;
                }

            }
        }
        public void searchApp(object sender, KeyEventArgs e)
        {
            if(e.KeyValue == 13) // that's a enter
            {
                searchPackageThenDisplay(searchBox.Text.ToLower());
            }
            
        }

        private void exit_Click(object sender, EventArgs e)
        {
            this.Close();
        }
        private void minimize_Click(object sender, EventArgs e)
        {
            this.WindowState = FormWindowState.Minimized;
        }

        private void available_and_installed_Click(object sender, EventArgs e)
        {
            modeIsAvailableOrInstalled = !modeIsAvailableOrInstalled;
            if(modeIsAvailableOrInstalled)
            {
                // switch selected
                this.available.ForeColor = Color.Black;
                this.available.BackColor = Color.White;

                this.Installed.ForeColor = Color.White;
                this.Installed.BackColor = Color.Black;
            } else
            {
                // switch selected
                this.available.ForeColor = Color.White;
                this.available.BackColor = Color.Black;

                this.Installed.ForeColor = Color.Black;
                this.Installed.BackColor = Color.White;
            }
        }
        private bool Download(string url, string outputPath)
        {
            try
            {
                // dowload file
                using (var client = new HttpClient())
                {
                    using (var s = client.GetStreamAsync(url))
                    {
                        using (var fs = new FileStream(outputPath, FileMode.OpenOrCreate))
                        {
                            s.Result.CopyTo(fs);
                        }
                    }
                }
                if(!File.Exists(outputPath))
                {
                    return false;
                }
                return true;

            } catch {
                return false;
            }
        }

        private void completeRepoJson()
        {
            string json;
            foreach (var packageJson in Directory.GetFiles(appPath, "*.json", SearchOption.AllDirectories))
            {
                json = File.ReadAllText(packageJson);
                try
                {
                    AresApp data = JsonConvert.DeserializeObject<List<AresApp>>(json)[0];

                    for (int i = 0; i < appList.Count(); i++)
                    {
                        if (appList[i] != null && data != null)
                        {
                            if (appList[i].package == data.package)
                            {
                                if (appList[i].version == data.version) // up do date
                                {
                                    appList[i].installed = true;
                                }
                                else
                                {
                                    appList[i].last_update = appList[i].version;
                                }
                            }
                        }
                    }
                } catch
                {
                    MessageBox.Show("Invalid package json file manifest");
                }
                
            }
        }
        private void DisplayApp(AresApp app)
        {
            try
            {
                selectedApp = app; // select app

                label2.Visible = true;
                appBtnInstall.Visible = true; // install -> launch/update if an update

                if (app.installed)
                {
                    appBtnUninstall.Visible = true; // uninstall


                    if (app.last_update != app.version) // could update
                    {
                        appVersion.Text = "version: " + app.version + ", last: " + app.last_update;
                        appBtnInstall.Text = "Update";
                    }
                    else
                    {
                        appVersion.Text = "version: " + app.version;
                        appBtnInstall.Text = "Launch";
                    }
                }
                else
                {
                    appBtnInstall.Text = "Install";
                    appVersion.Text = "last: " + app.last_update;
                    appBtnInstall.Visible = true;
                    appBtnUninstall.Visible = false;
                }

                appDesc.Text = app.description;
                appName.Text = app.name;
                appIcon.Image = LoadImageFromUrl(app.image);
            } catch
            {
                MessageBox.Show("Error while loading app");
            }
            
             

        }

        private void DownloadPackage(AresApp app)
        {
            if(app != null)
            {
                string newPath = Path.Combine(appPath, app.package);
                if (!File.Exists(newPath)) // create new dir
                    Directory.CreateDirectory(newPath);

                // write manifest
                string manifest = Path.Combine(newPath, "manifest.json");
                var data = @"[{
  ""name"": """ + app.name + @""",
  ""description"": """ + app.description + @""",
  ""image"": """ + app.image + @""",
  ""version"": """ + app.version + @""",
  ""first_date"": """ + app.first_date + @""",
  ""last_update"": """ + app.last_update + @""",
  ""updates"": [""" + string.Join("\", \"", app.updates) + @"""],
  ""author"": """ + app.author + @""",
  ""license"": """ + app.license + @""",
  ""package"": """ + app.package + @""",
  ""platform"": [""" + string.Join("\", \"", app.platform) + @"""],
  ""url"": """ + app.url + @""",
  ""keywords"": [""" + string.Join("\", \"", app.keywords) + @"""],
  ""install_requires"": [""" + string.Join("\", \"", app.install_requires) + @"""],
  ""installed"": ""true"",
  ""disabled"": ""false"",
  ""isCmdTool"": """+app.isCmdTool.ToString()+@""",
  ""startUpFile"": """+app.startUpFile+ @"""
}]";
                File.WriteAllText(manifest, data);

                // then download file
                string[] urlSplitted = app.url.Split("/");
                string finalFileName = urlSplitted[urlSplitted.Length-1];
                string outputFile = Path.Combine(newPath, finalFileName);
                if(Download(app.url, outputFile))
                {
                    if(app.isZipped)
                    { // unzip
                        if(outputFile.ToLower().EndsWith(".zip"))
                            System.IO.Compression.ZipFile.ExtractToDirectory(outputFile, newPath);
                    }
                    if(app.isInstaller) // install using installer exe
                    {
                        if(File.Exists(outputFile)) // installer path
                        {
                            // start installer
                            ProcessStartInfo psi = new ProcessStartInfo
                            {
                                FileName = outputFile,
                                Arguments = newPath,
                                UseShellExecute = true
                            };

                            Process.Start(psi);
                        } else
                        {
                            MessageBox.Show("Installer not found error, could not install");
                        }
                    }

                    MessageBox.Show(app.name+", is successfully installed!");
                    app.installed = true;
                    appBtnInstall.Text = "Launch";
                    appBtnUninstall.Visible = true;
                } else
                {
                    MessageBox.Show("Error while downloading your application", "", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            } else
            {
                MessageBox.Show("Application you wan't to install is not available, retry", "", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
            
        } 
        private void FetchRepo(bool forceUpdate=false)
        {
            // create dir if not present
            if(!File.Exists(appPath))
            {
                Directory.CreateDirectory(appPath);
            }

            string repoFile = Path.Combine(appPath, "repo.json");

            Load:
            if (File.Exists(repoFile) && !forceUpdate)
            {
                appList.Clear(); // reset applist

                string json = File.ReadAllText(repoFile);
                List<AresApp> data = new List<AresApp>();
                try
                {
                    data = JsonConvert.DeserializeObject<List<AresApp>>(json);
                } catch {
                    MessageBox.Show("Invalid JSON data, couldn't fetch repository");
                }

                
                
                foreach (var item in data)
                {
                    appList.Add(item);
                }

            } 
            else 
            { 
                // download/update
                if (Download(repoUrl, repoFile))
                {
                    MessageBox.Show("Success download");
                    forceUpdate = false;
                    goto Load;
                }
                else
                {
                    MessageBox.Show("Repository update failed");
                }
            }

            completeRepoJson();
        }
    }
}
